dialogue.text:
Aquí tienes un ejemplo de un código en C++ que implementa una calculadora básica:

```cpp
#include <iostream>

using namespace std;

int main() {
    int opcion;
    float num1, num2;

    cout << "Calculadora" << endl;
    cout << "1. Suma" << endl;
    cout << "2. Resta" << endl;
    cout << "3. Multiplicacion" << endl;
    cout << "4. Division" << endl;
    cout << "Ingresa el número de la operación que deseas realizar: ";
    cin >> opcion;

    cout << "Ingresa el primer número: ";
    cin >> num1;
    cout << "Ingresa el segundo número: ";
    cin >> num2;

    switch(opcion) {
        case 1:
            cout << "Resultado: " << num1 + num2 << endl;
            break;
        case 2:
            cout << "Resultado: " << num1 - num2 << endl;
            break;
        case 3:
            cout << "Resultado: " << num1 * num2 << endl;
            break;
        case 4:
            if(num2 != 0) {
                cout << "Resultado: " << num1 / num2 << endl;
            } else {
                cout << "Error: no se puede dividir entre cero." << endl;
            }
            break;
        default:
            cout << "Opción inválida." << endl;
    }

    return 0;
}
```

Este código te permite seleccionar la operación que deseas realizar (suma, resta, multiplicación o división) y luego ingresar los dos números para realizar la operación. El resultado se mostrará en la pantalla.

